(* ============================================================ *)
(* PROGRAM: ST_01_MAIN                                         *)
(* DESC:    Main sequence — auto/manual mode, index sync,      *)
(*          feeder control, tact time measurement, analog I/O  *)
(* SOURCE:  01_MAIN.txt (XG5000 mnemonic)                      *)
(* TARGET:  XEC IEC 61131-3 Structured Text                    *)
(* DATE:    2026-03-16                                         *)
(* ============================================================ *)

PROGRAM ST_01_MAIN

VAR
    (* --- timers --- *)
    TON_T0000 : TON;   (* always-ON power-up delay 30 ms *)
    TON_T0001 : TON;   (* auto-mode delay 5 ms *)
    TON_T0002 : TON;   (* equipment-ON delay 200 ms *)
    TON_T0003 : TON;   (* auto-stop delay 5 ms *)
    TON_T0005 : TON;   (* buzzer-stop timeout 30 000 ms *)
    TON_T0011 : TON;   (* tact timer 500 ms base *)
    TON_T0013 : TON;   (* stop-switch delay 1 ms *)
    TON_T0018 : TON;   (* all-unit complete check 10 ms *)
    TON_T0021 : TON;   (* plunger tact *)
    TON_T0022 : TON;   (* spring-0.15 tact *)
    TON_T0023 : TON;   (* spring-0.23 tact *)
    TON_T0024 : TON;   (* damper tact *)
    TON_T0025 : TON;   (* grease tact *)
    TON_T0026 : TON;   (* core tact *)
    TON_T0027 : TON;   (* frame tact *)
    TON_T0028 : TON;   (* inspection tact *)
    TON_T0029 : TON;   (* conduction tact *)
    TON_T0031 : TON;   (* analog CH0 measurement *)
    TON_T0032 : TON;   (* analog CH1 measurement *)

    (* --- rising/falling edge detection previous values --- *)
    M00010_prev  : BOOL := FALSE;
    M0120A_prev  : BOOL := FALSE;
    M02206_prev  : BOOL := FALSE;
    M03206_prev  : BOOL := FALSE;
    M04209_prev  : BOOL := FALSE;
    M05202_prev  : BOOL := FALSE;
    M06209_prev  : BOOL := FALSE;
    M07204_prev  : BOOL := FALSE;
    M08202_prev  : BOOL := FALSE;
    M08252_prev  : BOOL := FALSE;
    M08206_prev  : BOOL := FALSE;
    M08201_prev  : BOOL := FALSE;
    M00307_prev  : BOOL := FALSE;
    M00055_prev  : BOOL := FALSE;
    M00016_prev  : BOOL := FALSE;
    M00180_prev  : BOOL := FALSE;
    M0018A_prev  : BOOL := FALSE;
    M0001C_prev  : BOOL := FALSE;
    M00122_prev  : BOOL := FALSE;
    M08208_prev  : BOOL := FALSE;
    P0000B_prev  : BOOL := FALSE;
    K00105_prev  : BOOL := FALSE;
    K00115_prev  : BOOL := FALSE;
    K00140_prev  : BOOL := FALSE;
    K00141_prev  : BOOL := FALSE;
    K00142_prev  : BOOL := FALSE;
    K00143_prev  : BOOL := FALSE;
    K00144_prev  : BOOL := FALSE;
    K00145_prev  : BOOL := FALSE;
    K00146_prev  : BOOL := FALSE;
    K00147_prev  : BOOL := FALSE;
    K00148_prev  : BOOL := FALSE;
    K00149_prev  : BOOL := FALSE;
    K0014A_prev  : BOOL := FALSE;
    K0014B_prev  : BOOL := FALSE;
    K0014C_prev  : BOOL := FALSE;
    K0014D_prev  : BOOL := FALSE;
    K0014E_prev  : BOOL := FALSE;
    K0014F_prev  : BOOL := FALSE;
    K00150_prev  : BOOL := FALSE;
    K00151_prev  : BOOL := FALSE;
    K00152_prev  : BOOL := FALSE;
    K00153_prev  : BOOL := FALSE;
    K00154_prev  : BOOL := FALSE;
    K00155_prev  : BOOL := FALSE;
    K00156_prev  : BOOL := FALSE;
    K00157_prev  : BOOL := FALSE;
    K00104_prev  : BOOL := FALSE;
    M01101_prev  : BOOL := FALSE;
    M01102_prev  : BOOL := FALSE;
    M01103_prev  : BOOL := FALSE;
    M01104_prev  : BOOL := FALSE;
    M01105_prev  : BOOL := FALSE;
    M01106_prev  : BOOL := FALSE;
    M01107_prev  : BOOL := FALSE;
    M01108_prev  : BOOL := FALSE;
    M0110B_prev  : BOOL := FALSE;
    M01109_prev  : BOOL := FALSE;
    M02004_prev  : BOOL := FALSE;
    M03004_prev  : BOOL := FALSE;
END_VAR


(* ============================================================ *)
(* Rung 0: equipment power-up timers                           *)
(* F00099(_ON) always TRUE -> T0000 30ms, T0002 200ms          *)
(* ============================================================ *)
TON_T0000(IN := TRUE, PT := T#30ms);
T0000 := TON_T0000.Q;   (* M00306 source — equipment ready *)

TON_T0002(IN := TRUE, PT := T#200ms);
T0002 := TON_T0002.Q;   (* general power-up delay *)


(* ============================================================ *)
(* Rung 9: auto start condition -> SET M0000A                  *)
(* M00020 AND M00015 AND NOT M00180 AND NOT M0018A             *)
(* AND NOT M0013A AND M00303                                    *)
(* ============================================================ *)
IF M00020 AND M00015 AND NOT M00180 AND NOT M0018A
   AND NOT M0013A AND M00303 THEN
    M0000A := TRUE;   (* auto delay SET — M0000A 자동지연 SET *)
END_IF;


(* ============================================================ *)
(* Rung 16: auto delay timer -> M00010 auto mode               *)
(* M0000A -> TON T0001 5ms -> M00010                           *)
(* ============================================================ *)
TON_T0001(IN := M0000A, PT := T#5ms);
T0001 := TON_T0001.Q;
M00010 := T0001;   (* M00010 자동모드 *)


(* ============================================================ *)
(* Rung 23: auto mode rising edge -> init counters/registers   *)
(* M00010 P(rising) -> D00140,D00150,D00160,D00165 := 0       *)
(* ============================================================ *)
IF M00010 AND NOT M00010_prev THEN
    D00140 := 0;   (* plunger count init — 플런저 카운트 초기화 *)
    D00150 := 0;   (* spring-0.15 count init *)
    D00160 := 0;   (* spring-0.23 count init *)
    D00165 := 0;   (* damper NG count init *)
END_IF;


(* ============================================================ *)
(* Rung 33: alarm number register                              *)
(* M00010 -> D00188:=1, else D00188:=0                        *)
(* ============================================================ *)
IF M00010 THEN
    D00188 := 1;
ELSE
    D00188 := 0;
END_IF;


(* ============================================================ *)
(* Rung 39: auto cancel / EMO reset                            *)
(* M00302 -> RST M0000A                                        *)
(* M00012 -> RST M00030 (EMO solenoid reset — safety)         *)
(* ============================================================ *)
IF M00302 THEN
    M0000A := FALSE;
END_IF;
IF M00012 THEN
    M00030 := FALSE;   (* EMO solenoid RST — 비상정지 솔레노이드 RST *)
END_IF;


(* ============================================================ *)
(* Rung 43: auto/manual flag                                   *)
(* M00010 -> M00011                                            *)
(* ============================================================ *)
M00011 := M00010;   (* M00011 수동모드 (자동=수동 동기) *)


(* ============================================================ *)
(* Rung 45: auto-stop delay timer                              *)
(* M00010 -> TON T0003 5ms                                     *)
(* ============================================================ *)
TON_T0003(IN := M00010, PT := T#5ms);
T0003 := TON_T0003.Q;


(* ============================================================ *)
(* Rung 48: auto stop / alarm edge handling                    *)
(* T0003 AND M00304 -> SET M00012 (stop)                      *)
(* M00180 rising -> SET M0007C                                 *)
(* M0018A rising -> SET M0018A (minor alarm re-trigger)       *)
(* ============================================================ *)
IF T0003 AND M00304 THEN
    M00012 := TRUE;   (* auto stop SET — 자동 정지 *)
END_IF;

IF M00180 AND NOT M00180_prev THEN
    M0007C := TRUE;   (* alarm trigger SET — 알람 발생 *)
END_IF;


(* ============================================================ *)
(* Rung 58: auto-stop release                                  *)
(* M00012 AND M00020 AND NOT M00180 -> RST M00012, SET M0000A *)
(* ============================================================ *)
IF M00012 AND M00020 AND NOT M00180 THEN
    M00012 := FALSE;
    M0000A := TRUE;
END_IF;


(* ============================================================ *)
(* Rung 64: stop-switch delay timer                            *)
(* M00304 -> TON T0013 1ms                                     *)
(* ============================================================ *)
TON_T0013(IN := M00304, PT := T#1ms);
T0013 := TON_T0013.Q;


(* ============================================================ *)
(* Rung 67: stop-switch rising edge -> production count reset  *)
(* M00307 P -> M00150 := FALSE                                 *)
(* ============================================================ *)
IF M00307 AND NOT M00307_prev THEN
    M00150 := FALSE;   (* production count reset — 생산수량 리셋 *)
END_IF;


(* ============================================================ *)
(* Rung 70: all-unit work complete flag (M00018)               *)
(* M01110 (product present) AND all unit done bits             *)
(* AND NOT T0018                                               *)
(* ============================================================ *)
M00018 := (M01110 OR M01101) AND (M01102 OR M01112)
        AND (M01103 OR M01113) AND (M01104 OR M01114)
        AND (M01105 OR M01115) AND (M01106 OR M01116)
        AND (M01107 OR M01117) AND (M01108 OR M01118)
        AND (M0110B OR M01125) AND (M01109 OR M01119)
        AND NOT T0018;

TON_T0018(IN := M00018, PT := T#10ms);
T0018 := TON_T0018.Q;   (* all-unit complete one-shot *)


(* ============================================================ *)
(* Rung 111: buzzer-stop touch (K00105) rising -> SET M0001E  *)
(* ============================================================ *)
IF K00105 AND NOT K00105_prev THEN
    M0001E := TRUE;   (* buzzer stop SET — 부저 정지 *)
END_IF;


(* ============================================================ *)
(* Rung 113: buzzer-stop release on timeout or alarm re-fire   *)
(* M0001E AND T0005 -> RST M0001E                             *)
(* M00180 rising OR M0018A rising -> RST M0001E               *)
(* TON T0005 30000ms                                           *)
(* ============================================================ *)
IF (M0001E AND T0005)
   OR (M00180 AND NOT M00180_prev)
   OR (M0018A AND NOT M0018A_prev) THEN
    M0001E := FALSE;   (* buzzer stop release *)
END_IF;

TON_T0005(IN := M0001E, PT := T#30000ms);
T0005 := TON_T0005.Q;
K01105 := M0001E;   (* HMI buzzer-stop lamp — 부저정지 터치 램프 *)


(* ============================================================ *)
(* Rung 127: reset handling                                    *)
(* K00104 AND M00307 -> M0001F SET, reset various fault flags  *)
(* P0000B rising within reset -> RST M02810 etc.               *)
(* ============================================================ *)
IF K00104 AND M00307 THEN
    M0001F := TRUE;   (* system reset flag *)

    IF P0000B AND NOT P0000B_prev THEN   (* reset pushbutton rising edge *)
        M02810 := FALSE;
    END_IF;

    M04812 := FALSE;
    M03810 := FALSE;
    M0580E := FALSE;
    M0581E := FALSE;
    M0581A := FALSE;
    M0581B := FALSE;
    M0581C := FALSE;
END_IF;


(* ============================================================ *)
(* Rung 149: equipment ON initial state                        *)
(* T0000 AND M00306 -> RST M00030 (EMO release on power-up)   *)
(* ============================================================ *)
IF T0000 AND M00306 THEN
    M00030 := FALSE;   (* EMO release on power-up — 전원투입시 EMO 해제 *)
END_IF;


(* ============================================================ *)
(* Rung 152: all-unit home position flag (M00020)              *)
(* ============================================================ *)
M00020 := M01000 AND M02000 AND M03000 AND M04000
        AND M05000 AND M06000 AND M07000 AND M08000
        AND M09000 AND M00311 AND M08007
        AND NOT M01101 AND NOT M01104 AND NOT M01105;


(* ============================================================ *)
(* Rung 169: home position move command                        *)
(* M00011 AND M00300 AND NOT M00180 AND K00115 P -> SET M00021 *)
(* ============================================================ *)
IF M00011 AND M00300 AND NOT M00180 THEN
    IF K00115 AND NOT K00115_prev THEN
        M00021 := TRUE;   (* home move command SET — 초기위치 이동 *)
    END_IF;
END_IF;
M00055 := M00021;   (* servo rotation complete linked to home move *)


(* ============================================================ *)
(* Rung 177: home move complete -> RST M00021                  *)
(* M00021 AND M00020 -> RST M00021                             *)
(* M00011 AND NOT F0009A -> SET M00030 (EMO), SET M00304      *)
(* ============================================================ *)
IF M00021 AND M00020 THEN
    M00021 := FALSE;
END_IF;

IF M00011 AND NOT F0009A THEN
    M00030 := TRUE;    (* EMO solenoid SET on manual+power-off *)
    M00304 := TRUE;
END_IF;


(* ============================================================ *)
(* Rung 186~393: feeder ON/OFF control (HMI K-area touches)   *)
(* Pattern: K-touch SET rising / K-touch RST rising or !M00010 *)
(* ============================================================ *)

(* Rung 186: plunger-B feeder — 플런저 B 피더 *)
IF K00140 AND NOT K00140_prev AND M01987 THEN
    M00060 := TRUE;
END_IF;
IF (K00141 AND NOT K00141_prev) OR NOT M00010 THEN
    M00060 := FALSE;
END_IF;

(* Rung 202: plunger-L feeder — 플런저 L 피더 *)
IF K00142 AND NOT K00142_prev AND M01987 THEN
    M00061 := TRUE;
END_IF;
IF (K00143 AND NOT K00143_prev) OR NOT M00010 THEN
    M00061 := FALSE;
END_IF;

(* Rung 218: spring-0.15-B feeder — 스프링 0.15 B 피더 *)
IF K00144 AND NOT K00144_prev AND M01987 THEN
    M00062 := TRUE;
END_IF;
IF (K00145 AND NOT K00145_prev) OR NOT M00010 THEN
    M00062 := FALSE;
END_IF;
IF M02004 AND NOT M02004_prev THEN   (* spring feeder auto-on rising edge *)
    M00062 := TRUE;
END_IF;

(* Rung 238: spring-0.15-L feeder — 스프링 0.15 L 피더 *)
IF K00146 AND NOT K00146_prev AND M01987 THEN
    M00063 := TRUE;
END_IF;
IF (K00147 AND NOT K00147_prev) OR NOT M00010 THEN
    M00063 := FALSE;
END_IF;

(* Rung 258: spring-0.23-B feeder — 스프링 0.23 B 피더 *)
IF K00148 AND NOT K00148_prev AND M01987 THEN
    M00064 := TRUE;
END_IF;
IF (K00149 AND NOT K00149_prev) OR NOT M00010 THEN
    M00064 := FALSE;
END_IF;
IF M03004 AND NOT M03004_prev THEN
    M00064 := TRUE;
END_IF;

(* Rung 278: spring-0.23-L feeder — 스프링 0.23 L 피더 *)
IF K0014A AND NOT K0014A_prev AND M01987 THEN
    M00065 := TRUE;
END_IF;
IF (K0014B AND NOT K0014B_prev) OR NOT M00010 THEN
    M00065 := FALSE;
END_IF;

(* Rung 298: damper-B feeder — 댐퍼 B 피더 *)
IF K0014C AND NOT K0014C_prev AND M01987 THEN
    M00066 := TRUE;
END_IF;
IF (K0014D AND NOT K0014D_prev) OR NOT M00010 THEN
    M00066 := FALSE;
END_IF;

(* Rung 314: damper-L feeder — 댐퍼 L 피더 *)
IF K0014E AND NOT K0014E_prev AND M01987 THEN
    M00067 := TRUE;
END_IF;
IF (K0014F AND NOT K0014F_prev) OR NOT M00010 THEN
    M00067 := FALSE;
END_IF;

(* Rung 330: core-B feeder — 코어 B 피더 *)
IF K00150 AND NOT K00150_prev AND M01987 THEN
    M00068 := TRUE;
END_IF;
IF (K00151 AND NOT K00151_prev) OR NOT M00010 THEN
    M00068 := FALSE;
END_IF;

(* Rung 346: core-L feeder — 코어 L 피더 *)
IF K00152 AND NOT K00152_prev AND M01987 THEN
    M00069 := TRUE;
END_IF;
IF (K00153 AND NOT K00153_prev) OR NOT M00010 THEN
    M00069 := FALSE;
END_IF;

(* Rung 362: frame-B feeder — 프레임 B 피더 *)
IF K00154 AND NOT K00154_prev AND M01987 THEN
    M0006A := TRUE;
END_IF;
IF (K00155 AND NOT K00155_prev) OR NOT M00010 THEN
    M0006A := FALSE;
END_IF;

(* Rung 378: frame-L feeder — 프레임 L 피더 *)
IF K00156 AND NOT K00156_prev AND M01987 THEN
    M0006B := TRUE;
END_IF;
IF (K00157 AND NOT K00157_prev) OR NOT M00010 THEN
    M0006B := FALSE;
END_IF;


(* ============================================================ *)
(* Rung 394~440: feeder status -> HMI lamp output              *)
(* M000xx -> K011xx (touch lamp reflect)                       *)
(* ============================================================ *)
K01140 := M00060;   (* plunger-B feeder lamp *)
K01141 := M00060;
K01142 := M00061;   (* plunger-L feeder lamp *)
K01143 := M00061;
K01144 := M00062;   (* spring-0.15-B feeder lamp *)
K01145 := M00062;
K01146 := M00063;   (* spring-0.15-L feeder lamp *)
K01147 := M00063;
K01148 := M00064;   (* spring-0.23-B feeder lamp *)
K01149 := M00064;
K0114A := M00065;   (* spring-0.23-L feeder lamp *)
K0114B := M00065;
K0114C := M00066;   (* damper-B feeder lamp *)
K0114D := M00066;
K0114E := M00067;   (* damper-L feeder lamp *)
K0114F := M00067;
K01150 := M00068;   (* core-B feeder lamp *)
K01151 := M00068;
K01152 := M00069;   (* core-L feeder lamp *)
K01153 := M00069;
K01154 := M0006A;   (* frame-B feeder lamp *)
K01155 := M0006A;
K01156 := M0006B;   (* frame-L feeder lamp *)
K01157 := M0006B;


(* ============================================================ *)
(* Rung 442: tact time measurement — index tact (D07200 array) *)
(* M00010 AND M00055 rising -> SET M00016 (start tact)        *)
(* M00055 falling -> RST M00016 (stop tact)                   *)
(* TON T0011 500ms -> D07200 current tact value               *)
(* M00016 falling -> GMOVP: shift D07200+19 words to D07201   *)
(* ============================================================ *)
IF M00010 THEN
    IF M00055 AND NOT M00055_prev THEN
        M00016 := TRUE;   (* tact start *)
    END_IF;
    IF NOT M00055 AND M00055_prev THEN
        M00016 := FALSE;  (* tact stop *)
    END_IF;
END_IF;

TON_T0011(IN := M00016, PT := T#500ms);
T0011 := TON_T0011.Q;
D07200 := INT_TO_WORD(T0011);   (* store current tact value *)

IF NOT M00016 AND M00016_prev THEN
    (* GMOVP D07200 -> D07201, 19 words: tact history shift *)
    (* TODO: implement array block-shift for tact log *)
    ;
END_IF;


(* ============================================================ *)
(* Rung 464: plunger unit tact — 플런저 유닛 택트              *)
(* M00010 AND M0120A rising -> SET M00031                      *)
(* M01211 -> RST M00031                                        *)
(* ============================================================ *)
IF M00010 AND M0120A AND NOT M0120A_prev THEN
    M00031 := TRUE;
END_IF;
IF M01211 THEN
    M00031 := FALSE;
END_IF;
TON_T0021(IN := M00031, PT := T#500ms);
T0021 := TON_T0021.Q;
D07300 := INT_TO_WORD(T0021);
IF NOT M00031 AND M00031_prev THEN
    (* GMOVP D07300 -> D07301, 10 words *)
    ;
END_IF;


(* Rung 485: spring-0.15 tact — 스프링 0.15 택트 *)
IF M00010 AND M02206 AND NOT M02206_prev THEN
    M00032 := TRUE;
END_IF;
IF M01102 AND NOT M01102_prev THEN
    M00032 := FALSE;
END_IF;
TON_T0022(IN := M00032, PT := T#500ms);
T0022 := TON_T0022.Q;
D07320 := INT_TO_WORD(T0022);
IF NOT M00032 AND M00032_prev THEN
    (* GMOVP D07320 -> D07321, 10 words *)
    ;
END_IF;


(* Rung 507: spring-0.23 tact — 스프링 0.23 택트 *)
IF M00010 AND M03206 AND NOT M03206_prev THEN
    M00033 := TRUE;
END_IF;
IF M01103 AND NOT M01103_prev THEN
    M00033 := FALSE;
END_IF;
TON_T0023(IN := M00033, PT := T#500ms);
T0023 := TON_T0023.Q;
D07340 := INT_TO_WORD(T0023);
IF NOT M00033 AND M00033_prev THEN
    (* GMOVP D07340 -> D07341, 10 words *)
    ;
END_IF;


(* Rung 529: damper tact — 체크댐퍼 택트 *)
IF M00010 AND M04209 AND NOT M04209_prev THEN
    M00034 := TRUE;
END_IF;
IF M01104 AND NOT M01104_prev THEN
    M00034 := FALSE;
END_IF;
TON_T0024(IN := M00034, PT := T#500ms);
T0024 := TON_T0024.Q;
D07360 := INT_TO_WORD(T0024);
IF NOT M00034 AND M00034_prev THEN
    (* GMOVP D07360 -> D07361, 10 words *)
    ;
END_IF;


(* Rung 551: grease tact — 구리스 도포 택트 *)
IF M00010 AND M05202 AND NOT M05202_prev THEN
    M00035 := TRUE;
END_IF;
IF M01105 THEN
    M00035 := FALSE;
END_IF;
TON_T0025(IN := M00035, PT := T#500ms);
T0025 := TON_T0025.Q;
D07380 := INT_TO_WORD(T0025);
IF NOT M00035 AND M00035_prev THEN
    (* GMOVP D07380 -> D07381, 10 words *)
    ;
END_IF;


(* Rung 572: core tact — 코어 택트 *)
IF M00010 AND M06209 AND NOT M06209_prev THEN
    M00036 := TRUE;
END_IF;
IF M01106 AND NOT M01106_prev THEN
    M00036 := FALSE;
END_IF;
TON_T0026(IN := M00036, PT := T#500ms);
T0026 := TON_T0026.Q;
D07400 := INT_TO_WORD(T0026);
IF NOT M00036 AND M00036_prev THEN
    (* GMOVP D07400 -> D07401, 10 words *)
    ;
END_IF;


(* Rung 594: frame tact — 프레임 택트 *)
IF M00010 AND M07204 AND NOT M07204_prev THEN
    M00037 := TRUE;
END_IF;
IF M01107 THEN
    M00037 := FALSE;
END_IF;
TON_T0027(IN := M00037, PT := T#500ms);
T0027 := TON_T0027.Q;
D07420 := INT_TO_WORD(T0027);
IF NOT M00037 AND M00037_prev THEN
    (* GMOVP D07420 -> D07421, 10 words *)
    ;
END_IF;


(* Rung 615: inspection tact — 작동력검사 택트 *)
IF M00010 AND M08202 AND NOT M08202_prev THEN
    M00038 := TRUE;
END_IF;
IF M01108 THEN
    M00038 := FALSE;
END_IF;
TON_T0028(IN := M00038, PT := T#500ms);
T0028 := TON_T0028.Q;
D07440 := INT_TO_WORD(T0028);
IF NOT M00038 AND M00038_prev THEN
    (* GMOVP D07440 -> D07441, 10 words *)
    ;
END_IF;


(* Rung 636: conduction tact — 통전 택트 *)
IF M08252 AND NOT M08252_prev THEN
    M00039 := TRUE;   (* conduction tact start SET *)
END_IF;
IF M0110B THEN
    M00039 := FALSE;  (* conduction tact stop RST *)
END_IF;
TON_T0029(IN := M00039, PT := T#500ms);
T0029 := TON_T0029.Q;
D07460 := INT_TO_WORD(T0029);
IF NOT M00039 AND M00039_prev THEN
    (* GMOVP D07460 -> D07461, 10 words *)
    ;
END_IF;


(* ============================================================ *)
(* Rung 657: actuation-force analog tact                       *)
(* M08206 rising -> SET M00039 (reuse for analog tact start)   *)
(* M08208 -> RST M00039                                        *)
(* D00530 -> D07460, D00532 -> D07480                          *)
(* ============================================================ *)
IF M08206 AND NOT M08206_prev THEN
    M00039 := TRUE;
END_IF;
IF M08208 THEN
    M00039 := FALSE;
END_IF;
D07460 := D00530;   (* leakage current value -> tact log *)
D07480 := D00532;   (* flow value -> tact log *)
IF NOT M00039 AND M00039_prev THEN
    (* GMOVP D07460 -> D07461, 10 words *)
    (* GMOVP D07480 -> D07481, 10 words *)
    ;
END_IF;


(* ============================================================ *)
(* Rung 681: analog module (slot 0A) data read                 *)
(* U0A.02(_0A_CH0_DATA) -> D00500                              *)
(* U0A.03(_0A_CH1_DATA) -> D00498                              *)
(* ============================================================ *)
D00500 := U0A_02;   (* CH0 A/D converted value *)
D00498 := U0A_03;   (* CH1 A/D converted value *)


(* ============================================================ *)
(* Rung 686: CH0 leakage measurement                           *)
(* condition: U0A.00.F(RDY) AND M01987 AND NOT M0198A          *)
(*            AND M08206 AND U0A.01.0(CH0_ACK)                  *)
(* D00500*1 -> D00502, D00502/4 -> D00530                      *)
(* TON T0031 with D00534 as preset                             *)
(* ============================================================ *)
