(* Rung 726: flow judgment (upper/lower limit)                  *)
(* M08205 AND M01987 AND NOT M0198B                            *)
(* D00524<=D00532 AND D00522>=D00532 -> SET M08234 (OK)       *)
(* D00524>D00532 -> SET M08235 (NG high)                      *)
(* D00522<D00532 -> MOVP D00532->D00203                       *)
(* ============================================================ *)
