(* Rung 351: consecutive NG count alarm                        *)
(* DWORD comparison: D02110 >= D02112 -> SET M00814            *)
(* DMOVP 0 -> D02110 on SET                                   *)
(* D02110 < D02112 -> RST M00814                              *)
(* D02112 = 0 -> clear                                        *)
(* ============================================================ *)
IF (WORD_TO_DWORD(D02110) + WORD_TO_DWORD(D02110_HI)) >=
   (WORD_TO_DWORD(D02112) + WORD_TO_DWORD(D02112_HI)) THEN
    M00814 := TRUE;    (* consecutive NG alarm SET — 연속불량 알람 *)
    K00185 := TRUE;    (* HMI consecutive NG lamp *)
    D02110    := 0;    (* DMOVP 0 -> D02110: clear consecutive NG counter *)
    D02110_HI := 0;
END_IF;
IF (WORD_TO_DWORD(D02110) + WORD_TO_DWORD(D02110_HI)) <
   (WORD_TO_DWORD(D02112) + WORD_TO_DWORD(D02112_HI)) THEN
    M00814 := FALSE;
END_IF;
IF D02112 = 0 THEN
    M00814 := FALSE;
END_IF;


