(* ============================================================ *)
(* Rung 909: M0011F AND T0000 AND M00803 AND M00301 AND M00030 *)
(* power-up servo not ready -> machine alarm                   *)
(* ============================================================ *)
IF M0011F AND T0000 THEN
    M00803 := M00301 AND M00030;
END_IF;


(* ============================================================ *)
(* Rung 914: EMO (P00095) -> alarm code 65 output             *)
(* P00095 AND NOT M00009 AND M00840 -> D00189 := 65           *)
(* ============================================================ *)
IF P00095 AND NOT M00009 AND M00840 THEN
    D00189 := 65;   (* EMO alarm code — 비상정지 알람 코드 *)
END_IF;


(* ============================================================ *)
(* Rung 922: M00180 (alarm active) -> D00189 := 0 (clear)     *)
(* NOTE: This runs AFTER all code outputs above —               *)
(*       alarm active state clears display code back to 0      *)
(* ============================================================ *)
IF M00180 THEN
    D00189 := 0;
END_IF;


(* ============================================================ *)
(* Edge detection update                                       *)
(* ============================================================ *)
M00057_prev := M00057;
M0820E_prev := M0820E;
M08202_prev := M08202;

END_PROGRAM
